#include <bits/stdc++.h>
using namespace std;

const int N=7010,mod=998244353;

int T,f[N],cnt,sum;
long long n,a[N],b[N];

int main(){
    scanf("%d",&T);
    while(T--){
        scanf("%lld",&n);
        cnt=sum=0;
        for(int i=1;1ll*i*i<=n;i++)
            if(n%i==0){
                a[++cnt]=i;
                if(n/i!=i)
                    b[++sum]=n/i;
            }
        reverse(b+1,b+sum+1);
        for(int i=cnt+1;i<=cnt+sum;i++)
            a[i]=b[i-cnt];
        cnt+=sum;
        for(int i=1;i<=cnt;i++)
            f[i]=0;
        f[1]=1;
        for(register int i=1,num=cnt;i<cnt;++i){
            while((__int128)a[num]*a[i+1]>n)
                num--;
            for(register int j=num,k=cnt;j;--j){
                if(!f[j])
                    continue;
                while(a[k]>(__int128)a[j]*a[i+1] && k)
                    k--;
                if(n/a[j]%a[i+1]==0)
                    f[k]=(f[k]+f[j])%mod;
            }
        }
        printf("%d\n",(mod-1+f[cnt])%mod);
    }
    return 0;
}
